import{_ as e}from"./_plugin-vue_export-helper.cdc0426e.js";import{o,c,a as n,b as s,d as t,e as d,r as p}from"./app.fea91a44.js";const i={},l=d(`<p>编程语言一般都拥有数据类型的概念，不同的数据类型决定了运行时不同的处理方式，但 CSS 也拥有数据类型是我万万没想到的。</p><p>在我的认知中，CSS 与 HTML 一样，只是用于被浏览器读取解析的文本，学习 CSS 的方式也只是强记一些常用的属性与它们的作用，从未规范的学习过 CSS 的相关知识，也是因为觉得 CSS 相关知识有点薄弱，所以买了本 《CSS 新世界》，从中才知道了 CSS 也是拥有数据类型的。</p><h2 id="css-数据类型" tabindex="-1"><a class="header-anchor" href="#css-数据类型" aria-hidden="true">#</a> CSS 数据类型</h2><p>CSS 中的数据类型指的是被 <code>&lt;</code> 和 <code>&gt;</code> 包裹的结构，它是一系列 <strong>CSS 属性值</strong> 和其他数据结构的组合，限制了 CSS 属性的有效取值范围。</p><p>举个栗子，我们常见的 CSS 属性 <code>background-image</code>，它的有效取值是 <code>none | &lt;image&gt;</code>，其中 <code>none</code> 是一个关键字，表示无；而 <code>&lt;image&gt;</code> 就是一个数据结构，它包含以下属性和数据结构：</p><ul><li>&lt;url&gt;</li><li>&lt;gradient&gt;</li><li>element()</li></ul><p>那么 CSS 数据类型有什么用呢，看起来就是将一堆 CSS 属性值组合到一起而已。没错，仅仅只是把 CSS 属性值组合到一起，却能减少我们记忆的开销；试想一下，如果我们想要知道常用属性对应的合法属性值，那需要记忆的成本就非常大了，但现在我们以数据类型的方式记忆，只需要知道属性对应的数据类型就能够知道这个属性的合法取值是什么。</p><h2 id="css-属性值定义语法" tabindex="-1"><a class="header-anchor" href="#css-属性值定义语法" aria-hidden="true">#</a> CSS 属性值定义语法</h2><p>数据类型决定了某个属性的有效取值，而语法则规定了应该怎么排列、书写这些数据类型。</p><p>CSS 属性定义语法包含三个部分，即：符号、关键字、数据结构；以线性渐变 <code>linear-gradient</code> 为例，它的语法如下图：</p><p><img src="http://qkc148.bvimg.com/18470/7e751dcca13d1954.png" alt="CSS 属性值语法" loading="lazy"></p><h3 id="关键字" tabindex="-1"><a class="header-anchor" href="#关键字" aria-hidden="true">#</a> 关键字</h3><p>关键字分为通用关键字和全局关键字；通用关键字只被部分 CSS 属性支持，如：auto、none、ease 等；全局关键字可用于所有 CSS 属性，它的值有：</p><ul><li>inherit - 继承</li><li>initial - 重置属性值为 <strong>CSS 规范定义的初始值</strong></li><li>unset - 属性支持继承则等于 inherit，否则等于 initial</li><li>revert - 重置属性值为 <strong>浏览器默认设置的初始值</strong></li></ul><h3 id="符号" tabindex="-1"><a class="header-anchor" href="#符号" aria-hidden="true">#</a> 符号</h3><p>符号有字面符号、组合符号、数量符号，它们的含义如下表：</p><p>字面符号</p><table><thead><tr><th>符号</th><th>名称</th><th>描述</th></tr></thead><tbody><tr><td>,</td><td>并列分隔符</td><td>分隔并列值及函数参数</td></tr><tr><td>/</td><td>缩写分隔符</td><td>分隔一个值的多个部分、用于部分函数中</td></tr></tbody></table><p>缩写分隔符可用于分隔如 <code>font</code> 属性中 <code>font-size</code> 与 <code>line-height</code> 的值，又或者是 <code>background</code> 属性中 <code>background-position</code> 与 <code>background-size</code> 的值。</p><p>组合符号</p><table><thead><tr><th>符号</th><th>名称</th><th>描述</th></tr></thead><tbody><tr><td></td><td>并列</td><td>空格，表示各部分必须出现且按顺序出现</td></tr><tr><td>&amp;&amp;</td><td>与</td><td>表示各部分必须出现，但可以不按顺序出现</td></tr><tr><td>||</td><td>或</td><td>各部分至少出现一个，也可以同时存在，可以不按顺序出现</td></tr><tr><td>|</td><td>互斥</td><td>各部分只能出现一个</td></tr><tr><td>[]</td><td>方括号</td><td>提升计算优先级</td></tr></tbody></table><p>数量符号</p><table><thead><tr><th>符号</th><th>名称</th><th>描述</th></tr></thead><tbody><tr><td></td><td>无</td><td>出现一次</td></tr><tr><td>*</td><td>星号</td><td>出现任意次</td></tr><tr><td>+</td><td>加号</td><td>出现一次或多次</td></tr><tr><td>?</td><td>问号</td><td>不出现或一次</td></tr><tr><td>#</td><td>井号</td><td>同加号，但出现多次时必须以 , 分隔</td></tr><tr><td>!</td><td>叹号</td><td>分组必须产生一个值</td></tr></tbody></table><p>了解了这些，我们再看 <code>linear-gradient</code> 的语法就能很容易知道它的有效取值是什么了：</p><div class="language-css line-numbers-mode" data-ext="css"><pre class="language-css"><code><span class="token function">linear-gradient</span><span class="token punctuation">(</span> [ &lt;angle&gt; | to &lt;side-or-corner&gt; <span class="token punctuation">,</span>]? &lt;color-stop-list&gt; <span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>它的前半部分是一个分组，且使用了数量修饰符 <code>?</code>，表示它的前半部分是可有可无的，分组内部使用了 <code>|</code> 互斥符号，表示 <code>&lt;angle&gt;</code> 和 <code>to &lt;side-or-corner&gt;</code> 只能出现其中一个，后面还有一个 <code>,</code> 并列分隔符号，<code>?</code> 数量符号后还有一个空格符号，最后就是 <code>&lt;color-stop-list&gt;</code>，所以 <code>linear-gradient</code> 的有效语法有：</p><div class="language-css line-numbers-mode" data-ext="css"><pre class="language-css"><code><span class="token function">linear-gradient</span><span class="token punctuation">(</span> &lt;angle&gt;<span class="token punctuation">,</span> &lt;color-stop-list&gt; <span class="token punctuation">)</span>
<span class="token function">linear-gradient</span><span class="token punctuation">(</span> to &lt;side-or-corner&gt;<span class="token punctuation">,</span> &lt;color-stop-list&gt; <span class="token punctuation">)</span>
<span class="token function">linear-gradient</span><span class="token punctuation">(</span> &lt;color-stop-list&gt; <span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="浏览器渐进兼容处理" tabindex="-1"><a class="header-anchor" href="#浏览器渐进兼容处理" aria-hidden="true">#</a> 浏览器渐进兼容处理</h2><p>浏览器的历史原因导致了不同内核浏览器之间存在差异，不管是 <code>HTML</code>、<code>CSS</code>、还是 <code>JavaScript</code>；当项目需要兼容旧浏览器时，我们就需要对这些浏览器进行适配。</p><h3 id="语法差异实现兼容" tabindex="-1"><a class="header-anchor" href="#语法差异实现兼容" aria-hidden="true">#</a> 语法差异实现兼容</h3><p>适配的方法主要是利用语法差异实现兼容，如利用属性值语法的不同与 <code>CSS</code> 样式层叠的特性，浏览器在遇到不支持的 CSS 属性值语法时会默认忽略，我们可以先在前面设置一个被特定浏览器接受的 CSS 属性，然后通过层叠在后面设置不被特定浏览器接受但被现代浏览器接受的 CSS 属性。</p><p>像这种兼容处理的方式需要我们知道不同浏览器之间的差异并记忆大量它们之间共通的 CSS 属性，这是没有必要的，因为现在浏览器厂商之间都在往规范发展，而旧浏览器所占的市场份额只会越来越小，除非必要，我们只需要学习规范支持的 CSS 属性，当遇到需要兼容旧浏览器时再去查阅相关资料。</p><p>我们还能够通过 CSS 伪类和伪元素对浏览器进行区分，在 <code>IE9</code> 以前是不支持伪类和伪元素的，而 <code>IE10</code> 支持特定的伪类，如 <code>:required</code>、<code>:valid</code> 等。</p><h3 id="supports-特性检测" tabindex="-1"><a class="header-anchor" href="#supports-特性检测" aria-hidden="true">#</a> @supports 特性检测</h3><p><code>@supports</code> 是规范的渐进处理方式，它能够检查浏览器是否支持指定的 CSS 属性与属性值，但由于它是从 <code>Edge12</code> 才开始支持的，所以无法通过它对 <code>IE</code> 进行兼容处理，它的简单语法如下：</p><div class="language-css line-numbers-mode" data-ext="css"><pre class="language-css"><code><span class="token atrule"><span class="token rule">@supports</span> <span class="token punctuation">(</span><span class="token property">position</span><span class="token punctuation">:</span> sticky<span class="token punctuation">)</span></span> <span class="token punctuation">{</span>
  <span class="token selector">navbar</span> <span class="token punctuation">{</span>
    <span class="token property">position</span><span class="token punctuation">:</span> sticky<span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>同时，它还支持 <code>and</code>、<code>or</code>、<code>not</code> 等条件，比如：</p><div class="language-css line-numbers-mode" data-ext="css"><pre class="language-css"><code><span class="token atrule"><span class="token rule">@supports</span> <span class="token keyword">not</span> <span class="token punctuation">(</span><span class="token property">position</span><span class="token punctuation">:</span> sticky<span class="token punctuation">)</span></span> <span class="token punctuation">{</span>
  <span class="token selector">nabbar</span> <span class="token punctuation">{</span>
    <span class="token property">position</span><span class="token punctuation">:</span> relative<span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>它们还能组合使用，比如：</p><div class="language-css line-numbers-mode" data-ext="css"><pre class="language-css"><code><span class="token atrule"><span class="token rule">@supports</span> <span class="token punctuation">(</span><span class="token property">position</span><span class="token punctuation">:</span> relative<span class="token punctuation">)</span> <span class="token keyword">and</span> <span class="token punctuation">(</span><span class="token keyword">not</span> <span class="token property">position</span><span class="token punctuation">:</span> sticky<span class="token punctuation">)</span></span> <span class="token punctuation">{</span>
  <span class="token selector">nabbar</span> <span class="token punctuation">{</span>
    <span class="token property">position</span><span class="token punctuation">:</span> relative<span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>@supports</code> 还支持检查自定义属性以及函数，比如选择器 <code>selector</code> 函数：</p><p>自定义属性</p><div class="language-css line-numbers-mode" data-ext="css"><pre class="language-css"><code><span class="token atrule"><span class="token rule">@supports</span> <span class="token punctuation">(</span><span class="token property">--foo</span><span class="token punctuation">:</span> green<span class="token punctuation">)</span></span> <span class="token punctuation">{</span>
  <span class="token selector">body</span> <span class="token punctuation">{</span>
    <span class="token property">color</span><span class="token punctuation">:</span> <span class="token function">var</span><span class="token punctuation">(</span>--varName<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>selector</code> 函数</p><div class="language-css line-numbers-mode" data-ext="css"><pre class="language-css"><code><span class="token atrule"><span class="token rule">@supports</span> <span class="token function">selector</span><span class="token punctuation">(</span><span class="token selector-function-argument selector">:nth-child(even)</span><span class="token punctuation">)</span></span> <span class="token punctuation">{</span>
  // do something
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>@supports</code> 还支持内嵌其他 <code>@</code> 规则，包括它自己，能够以此来完成更复杂的判断。</p>`,46),r={href:"https://www.zhangxinxu.com/wordpress/2019/11/css-value-type/",target:"_blank",rel:"noopener noreferrer"},u={href:"https://developer.mozilla.org/en-US/docs/Web/CSS/alpha-value",target:"_blank",rel:"noopener noreferrer"},k=n("p",null,"-- end",-1),h=n("h2",{id:"参考资料",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#参考资料","aria-hidden":"true"},"#"),s(" 参考资料")],-1),v=n("br",null,null,-1),g={href:"https://developer.mozilla.org/en-US/docs/Web/CSS/alpha-value",target:"_blank",rel:"noopener noreferrer"};function b(S,m){const a=p("ExternalLinkIcon");return o(),c("div",null,[l,n("p",null,[s("最后推荐学习 CSS 数据结构的站点 "),n("a",r,[s("CSS值类型文档大全"),t(a)]),s(" 和 MDN 文档 "),n("a",u,[s("MDN#CSS_Types"),t(a)])]),k,h,n("blockquote",null,[n("p",null,[s("《CSS 新世界》"),v,n("a",g,[s("MDN#CSS_Types"),t(a)])])])])}const f=e(i,[["render",b],["__file","css 数据类型与兼容处理.html.vue"]]);export{f as default};
